#!/bin/bash

# Database credentials
DB_HOST=localhost
DB_USER=backup_user
DB_PASSWORD='BackupPass123'
DB_NAME=mydatabase

# Backup directory
BACKUP_DIR=/path/to/backup/directory

# Create backup directory if it doesn't exist
mkdir -p $BACKUP_DIR

# Get current date for backup file name
DATE=$(date +"%Y-%m-%d_%H-%M-%S")

